Future<void> main() async {
  final apiClient = ApiClient();

  try {
    // 1. Login
    final tokens = await apiClient.login(
      email: 'user@example.com',
      password: 'securePassword123!',
    );
    debugPrint('Logged in. Access token: ${tokens.accessToken.substring(0, 10)}…');

    // 2. Fetch profile
    final profile = await apiClient.getUserProfile();
    debugPrint('Hello, ${profile.displayName} (${profile.email})');

    // 3. Update profile
    final updated = await apiClient.updateUserProfile(
      displayName: 'New Display Name',
    );
    debugPrint('Updated name: ${updated.displayName}');

    // 4. Sync data
    final syncManager = SyncManager(apiClient: apiClient);

    syncManager.syncResults.listen((result) {
      debugPrint(
        'Sync complete – ↑${result.uploadedCount} ↓${result.downloadedCount}',
      );
    });

    // Push some local changes
    final syncResult = await syncManager.performSync(
      localChanges: [
        SyncData(
          id: 'item-1',
          type: 'note',
          payload: {'title': 'Hello', 'body': 'World'},
          updatedAt: DateTime.now(),
        ),
      ],
    );
    debugPrint('Manual sync: $syncResult');

    // Start background sync
    syncManager.startPeriodicSync(interval: const Duration(minutes: 5));

    // Fetch remote changes
    final remoteChanges = await apiClient.fetchRemoteChanges(
      since: DateTime.now().subtract(const Duration(days: 1)),
    );
    debugPrint('Remote changes: ${remoteChanges.length}');

    // Cleanup
    syncManager.dispose();
    await apiClient.logout();
  } on ApiException catch (e) {
    debugPrint('API error: $e');
  } on NetworkException catch (e) {
    debugPrint('Network error: $e');
  } finally {
    apiClient.dispose();
  }
}